// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract TimezoneHelper {

    function toTimestampWithOffset(
        uint256 year,
        uint256 month,
        uint256 day,
        uint256 hour,
        uint256 minute,
        int256 utcOffsetHours // e.g. +3 for EAT
    ) public pure returns (uint256) {

        // --- VALIDATION ---
        require(year >= 1970 && year <= 2100, "Invalid year");
        require(month >= 1 && month <= 12, "Invalid month");
        require(hour < 24, "Invalid hour");
        require(minute < 60, "Invalid minute");
        require(utcOffsetHours >= -12 && utcOffsetHours <= 14, "Invalid UTC offset");

        uint256 daysInMonth = _getDaysInMonth(year, month);
        require(day >= 1 && day <= daysInMonth, "Invalid day");

        // --- CONVERSION ---
        uint256 timestamp = _toTimestamp(year, month, day, hour, minute, 0);

        // Adjust timezone → convert to UTC
        if (utcOffsetHours > 0) {
            timestamp -= uint256(utcOffsetHours) * 1 hours;
        } else if (utcOffsetHours < 0) {
            timestamp += uint256(-utcOffsetHours) * 1 hours;
        }

        return timestamp;
    }

    function _toTimestamp(
        uint256 year,
        uint256 month,
        uint256 day,
        uint256 hour,
        uint256 minute,
        uint256 second
    ) internal pure returns (uint256 timestamp) {

        uint16 i;

        // Years
        for (i = 1970; i < year; i++) {
            if (_isLeapYear(i)) timestamp += 366 days;
            else timestamp += 365 days;
        }

        // Months
        uint8[12] memory monthDays = [
            uint8(31), 28, 31, 30, 31, 30,
            31, 31, 30, 31, 30, 31
        ];

        if (_isLeapYear(uint16(year))) {
            monthDays[1] = 29;
        }

        for (i = 1; i < month; i++) {
            timestamp += uint256(monthDays[i - 1]) * 1 days;
        }

        // Days + time
        timestamp += (day - 1) * 1 days;
        timestamp += hour * 1 hours;
        timestamp += minute * 1 minutes;
        timestamp += second;
    }

    function _getDaysInMonth(uint256 year, uint256 month) internal pure returns (uint256) {
        if (month == 2) {
            return _isLeapYear(uint16(year)) ? 29 : 28;
        } else if (
            month == 4 || month == 6 || month == 9 || month == 11
        ) {
            return 30;
        } else {
            return 31;
        }
    }

    function _isLeapYear(uint16 year) internal pure returns (bool) {
        if (year % 4 != 0) return false;
        if (year % 100 != 0) return true;
        if (year % 400 != 0) return false;
        return true;
    }
}

